import type { ChapterAssessment } from "../types";

type Case = ChapterAssessment["cases"][number];
type Probe = Case["probes"]["application"];
type Skill = keyof Case["probes"];
type Difficulty = Probe["difficulty"];
type Choice = readonly [text: string, feedback: string];
type Choices = readonly [Choice, Choice, Choice, Choice];
const IDS = ["a", "b", "c", "d"] as const;

function p(skill: Skill, difficulty: Difficulty, prompt: string, objectiveIds: [string, ...string[]], correct: 0 | 1 | 2 | 3, specs: Choices, reasoning: [string, ...string[]], takeaway: string, section: string, page: number): Probe {
  const choices = specs.map(([text, feedback], i) => ({ id: IDS[i], text, feedback })) as Probe["choices"];
  return { skill, difficulty, prompt, objectiveIds, choices, correctChoiceId: IDS[correct], reasoning, takeaway, references: [{ section, page }] };
}
function c(id: string, stimulus: Case["stimulus"], probes: Case["probes"]): Case { return { id, chapterId: 10, stimulus, probes }; }

